import React, { useEffect, useState } from 'react';
// This component displays data for a single turbine.  The dashboard is
// simplified to only show the first turbine (ID 1), so we do not use
// route parameters here.
// no router navigation is used, so we do not import Link from react‑router.
import { drawLineChart } from '../utils/chart';

function TurbineDetail() {
  // Use a fixed turbine ID.  Since this dashboard is designed for a single
  // turbine, we hard‑code the ID here instead of reading it from the URL.
  const id = 1;
  const [turbine, setTurbine] = useState(null);
  const [telemetry, setTelemetry] = useState([]);
  const [alarms, setAlarms] = useState([]);

  // Fetch turbine info and telemetry when id changes
  useEffect(() => {
    fetch(`/api/turbines`)
      .then(res => res.json())
      .then(data => {
        const t = data.find(x => x.id === Number(id));
        setTurbine(t);
      })
      .catch(err => console.error(err));
    fetch(`/api/telemetry/${id}`)
      .then(res => res.json())
      .then(data => setTelemetry(data))
      .catch(err => console.error(err));
    fetch(`/api/alarms`)
      .then(res => res.json())
      .then(data => setAlarms(data.filter(a => a.turbineId === Number(id))))
      .catch(err => console.error(err));
  }, [id]);

  // Draw charts when telemetry is updated
  useEffect(() => {
    if (telemetry.length === 0) return;
    const labels = telemetry.map(t => new Date(t.timestamp));
    const wind = telemetry.map(t => t.windSpeed);
    const power = telemetry.map(t => t.powerOutput);
    const vibration = telemetry.map(t => t.vibration);
    const temp = telemetry.map(t => t.temperature);
    drawLineChart('windSpeedChart', labels, wind, { yLabel: 'm/s', lineColor: '#007bff' });
    drawLineChart('powerOutputChart', labels, power, { yLabel: 'MW', lineColor: '#28a745' });
    drawLineChart('vibrationChart', labels, vibration, { yLabel: 'm/s²', lineColor: '#ffc107' });
    drawLineChart('temperatureChart', labels, temp, { yLabel: '°C', lineColor: '#dc3545' });
  }, [telemetry]);

  if (!turbine) {
    return <div className="container"><p>Loading...</p></div>;
  }

  return (
    <div className="container">
      <h1 className="my-4">{turbine.name} Details</h1>
      <p><strong>Site:</strong> {turbine.site}</p>
      <div className="row">
        <div className="col-md-6">
          <h2 className="h5">Wind Speed (last 24h)</h2>
          <canvas id="windSpeedChart" width="400" height="200"></canvas>
        </div>
        <div className="col-md-6">
          <h2 className="h5">Power Output (last 24h)</h2>
          <canvas id="powerOutputChart" width="400" height="200"></canvas>
        </div>
      </div>
      <div className="row mt-4">
        <div className="col-md-6">
          <h2 className="h5">Vibration (last 24h)</h2>
          <canvas id="vibrationChart" width="400" height="200"></canvas>
        </div>
        <div className="col-md-6">
          <h2 className="h5">Temperature (last 24h)</h2>
          <canvas id="temperatureChart" width="400" height="200"></canvas>
        </div>
      </div>
      <h2 className="h4 mt-5">Recent Alarms</h2>
      {alarms.length > 0 ? (
        <div className="table-responsive">
          <table className="table table-bordered">
            <thead className="table-light">
              <tr>
                <th>Time</th>
                <th>Description</th>
                <th>Severity</th>
              </tr>
            </thead>
            <tbody>
              {alarms.map(alarm => (
                <tr key={alarm.id}>
                  <td>{new Date(alarm.timestamp).toLocaleString()}</td>
                  <td>{alarm.description}</td>
                  <td><span className={`badge bg-${alarm.severity === 'critical' ? 'danger' : 'warning'}`}>{alarm.severity.charAt(0).toUpperCase() + alarm.severity.slice(1)}</span></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      ) : (
        <p>No alarms for this turbine in the last 24 hours.</p>
      )}
      {/* There is no separate dashboard page in the single‑turbine version,
          so we omit the back link. */}
    </div>
  );
}

export default TurbineDetail;
